package com.maum.backend.service

import com.maum.backend.entity.follow.FollowEntity
import com.maum.backend.exception.*
import com.maum.backend.repository.follow.FollowRepository
import com.maum.backend.repository.user.UserRepository
import org.springframework.stereotype.Service
import org.springframework.transaction.annotation.Transactional

@Service
class UserService(
    private val userRepository: UserRepository,
    private val followRepository: FollowRepository,
) {

    @Transactional
    fun follow(followerId: String, followeeId: String) {
        // 자기 자신 팔로우 방지
        if (followerId == followeeId) {
            throw SelfFollowException()
        }

        // 팔로우 대상 유저 존재 여부 확인
        if (!userRepository.existsById(followerId)) {
            throw UserNotFoundException(followerId)
        }
        if (!userRepository.existsById(followeeId)) {
            throw UserNotFoundException(followeeId)
        }

        // 중복 팔로우 방지
        if (followRepository.existsByFollowerIdAndFolloweeId(followerId, followeeId)) {
            throw AlreadyFollowingException(followerId, followeeId)
        }

        followRepository.save(
            FollowEntity(
                followerId = followerId,
                followeeId = followeeId,
            )
        )
    }

    @Transactional
    fun unfollow(followerId: String, followeeId: String) {
        if (!followRepository.existsByFollowerIdAndFolloweeId(followerId, followeeId)) {
            throw NotFollowingException(followerId, followeeId)
        }
        followRepository.deleteByFollowerIdAndFolloweeId(followerId, followeeId)
    }

    @Transactional(readOnly = true)
    fun getFollowings(userId: String): List<String> {
        if (!userRepository.existsById(userId)) {
            throw UserNotFoundException(userId)
        }
        return followRepository.findByFollowerId(userId).map { it.followeeId }
    }

    @Transactional(readOnly = true)
    fun getFollowers(userId: String): List<String> {
        if (!userRepository.existsById(userId)) {
            throw UserNotFoundException(userId)
        }
        return followRepository.findByFolloweeId(userId).map { it.followerId }
    }
}
```

